create table dirkspzm32.lvs_lgr_ort_cfg (
    sid                       varchar2(2 char) default '01' not null enable,
    firma_nr                  number(2, 0) default 1 not null enable,
    lgr_ort                   number(5, 0) not null enable,
    lgr_ort_cfg_param         varchar2(40 char) not null enable,
    lgr_ort_cfg_param_typ     varchar2(40 char) not null enable,
    lgr_ort_cfg_param_default varchar2(40 char),
    lgr_ort_cfg_param_ref_tab varchar2(40 char),
    created_date              date default sysdate not null enable,
    created_login_id          number(*, 0) default - 1 not null enable,
    last_change_date          date,
    last_change_login_id      number(*, 0)
);

alter table dirkspzm32.lvs_lgr_ort_cfg
    add constraint pk_lvs_lgr_ort_cfg
        primary key ( lgr_ort,
                      lgr_ort_cfg_param,
                      sid,
                      firma_nr )
            using index enable;


